// HasKeyResults applies the HasEdge predicate on the "key_results" edge.
func HasKeyResults() predicate.Objective {
	return predicate.Objective(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, KeyResultsTable, KeyResultsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasKeyResultsWith applies the HasEdge predicate on the "key_results" edge with a given conditions (other predicates).
func HasKeyResultsWith(preds ...predicate.KeyResult) predicate.Objective {
	return predicate.Objective(func(s *sql.Selector) {
		step := newKeyResultsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasReviews applies the HasEdge predicate on the "reviews" edge.
func HasReviews() predicate.Objective {
	return predicate.Objective(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, ReviewsTable, ReviewsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasReviewsWith applies the HasEdge predicate on the "reviews" edge with a given conditions (other predicates).
func HasReviewsWith(preds ...predicate.Review) predicate.Objective {
	return predicate.Objective(func(s *sql.Selector) {
		step := newReviewsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Objective) predicate.Objective {
	return predicate.Objective(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Objective) predicate.Objective {
	return predicate.Objective(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Objective) predicate.Objective {
	return predicate.Objective(sql.NotPredicates(p))
}
